  1	import type { FC } from 'react';
  2	import { TableCell } from 'src/modules/Providers/utils/components/TableCell/TableCell';
  3	import { TableEmptyCell } from 'src/modules/Providers/utils/components/TableCell/TableEmptyCell';
  4	import { PROVIDER_TYPES } from 'src/providers/utils/constants';
  5	import { useForkliftTranslation } from 'src/utils/i18n';
  6	
  7	import type { Concern } from '@kubev2v/types';
  8	import {
  9	  Button,
 10	  ButtonVariant,
 11	  Label,
 12	  Popover,
 13	  Split,
 14	  SplitItem,
 15	  Stack,
 16	  StackItem,
 17	} from '@patternfly/react-core';
 18	import { isEmpty } from '@utils/helpers';
 19	
 20	import { orderedConcernCategories } from '../constants';
 21	import {
 22	  getCategoryColor,
 23	  getCategoryIcon,
 24	  getCategoryTitle,
 25	} from '../utils/helpers/getCategoryTitle';
 26	import { groupConcernsByCategory } from '../utils/helpers/groupConcernsByCategory';
 27	
 28	import type { VMCellProps } from './VMCellProps';
 29	
 30	/**
 31	 * Renders a list of concerns.
 32	 *
 33	 * @param {Object} props - The properties of the ConcernList component.
 34	 * @param {Concern[]} props.concerns - The list of concerns to render.
 35	 * @returns {ReactElement} The rendered list of concerns.
 36	 */
 37	const ConcernList: FC<{ concerns: Concern[] }> = ({ concerns }) => (
 38	  <Stack>
 39	    {concerns.map((concern) => (
 40	      <StackItem key={concern.category}>
 41	        {getCategoryIcon(concern.category)} {concern.label}
 42	      </StackItem>
 43	    ))}
 44	  </Stack>
 45	);
 46	
 47	/**
 48	 * Renders a popover for a specific concern category.
 49	 *
 50	 * @param {Object} props - The properties of the ConcernPopover component.
 51	 * @param {string} props.category - The category of the concern.
 52	 * @param {Concern[]} props.concerns - The list of concerns for the category.
 53	 * @returns {ReactElement} The rendered popover.
 54	 */
 55	const ConcernPopover: FC<{
 56	  category: string;
 57	  concerns: Concern[];
 58	}> = ({ category, concerns }) => {
 59	  const { t } = useForkliftTranslation();
 60	
 61	  if (concerns.length < 1) return <></>;
 62	
 63	  return (
 64	    <Popover
 65	      aria-label={`${category} popover`}
 66	      headerContent={<div>{getCategoryTitle(category)}</div>}
 67	      bodyContent={<ConcernList concerns={concerns} />}
 68	      footerContent={t('Total: {{length}}', { length: concerns.length })}
 69	    >
 70	      <Button isInline variant={ButtonVariant.link}>
 71	        <Label color={getCategoryColor(category)} icon={getCategoryIcon(category)}>
 72	          {concerns.length}
 73	        </Label>
 74	      </Button>
 75	    </Popover>
 76	  );
 77	};
 78	
 79	/**
 80	 * Renders a table cell containing concerns grouped by category.
 81	 *
 82	 * @param {VMCellProps} props - The properties of the VMConcernsCellRenderer component.
 83	 * @returns {ReactElement} The rendered table cell.
 84	 */
 85	export const VMConcernsCellRenderer: FC<VMCellProps> = ({ data }) => {
 86	  const concerns: Concern[] =
 87	    data?.vm?.providerType === PROVIDER_TYPES.openshift ? [] : data?.vm?.concerns;
 88	  if (!concerns || isEmpty(concerns)) {
 89	    return <TableEmptyCell />;
 90	  }
 91	
 92	  const groupedConcerns = groupConcernsByCategory(concerns);
 93	
 94	  return (
 95	    <TableCell>
 96	      <Split hasGutter>
 97	        {orderedConcernCategories.map((category) => {
 98	          const hasConcernCategory = concerns?.find((concern) => concern.category === category);
 99	
100	          if (hasConcernCategory) {
101	            return (
102	              <SplitItem key={category}>
103	                <ConcernPopover category={category} concerns={groupedConcerns[category] || []} />
104	              </SplitItem>
105	            );
106	          }
107	
108	          return null;
109	        })}
110	      </Split>
111	    </TableCell>
112	  );
113	};

